#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="C:\HS\Dev\EduKo\node_modules\jsesc\bin\node_modules;C:\HS\Dev\EduKo\node_modules\jsesc\node_modules;C:\HS\Dev\EduKo\node_modules;C:\HS\Dev\node_modules;C:\HS\node_modules;C:\node_modules;C:\HS\Dev\EduKo\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/proc/cygdrive/c/HS/Dev/EduKo/node_modules/jsesc/bin/node_modules:/proc/cygdrive/c/HS/Dev/EduKo/node_modules/jsesc/node_modules:/proc/cygdrive/c/HS/Dev/EduKo/node_modules:/proc/cygdrive/c/HS/Dev/node_modules:/proc/cygdrive/c/HS/node_modules:/proc/cygdrive/c/node_modules:/proc/cygdrive/c/HS/Dev/EduKo/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../jsesc/bin/jsesc" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../jsesc/bin/jsesc" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../jsesc/bin/jsesc" $args
  } else {
    & "node$exe"  "$basedir/../jsesc/bin/jsesc" $args
  }
  $ret=$LASTEXITCODE
}
$env:NODE_PATH=$env_node_path
exit $ret
